                        {
                            context.EvaluatedKeywordForProperty(false, 20, RequiredPropertySpecIdNotPresent, "specId"u8, "required"u8);
                        }
                        else
                        {
                            context.EvaluatedKeywordForProperty(true, 20, RequiredPropertySpecIdPresent, "specId"u8, "required"u8);
                        }

                        if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForWorkspaceTargetHash] & RequiredBitForWorkspaceTargetHash) == 0)
                        {
                            context.EvaluatedKeywordForProperty(false, 21, RequiredPropertyWorkspaceTargetHashNotPresent, "workspaceTargetHash"u8, "required"u8);
                        }
                        else
                        {
                            context.EvaluatedKeywordForProperty(true, 21, RequiredPropertyWorkspaceTargetHashPresent, "workspaceTargetHash"u8, "required"u8);
                        }
                    }
                }
            }

            internal static bool Evaluate(
                IJsonDocument parentDocument,
                int parentIndex,
                IJsonSchemaResultsCollector? resultsCollector = null)
            {
                JsonSchemaContext context = JsonSchemaContext.BeginContext(
                parentDocument,
                parentIndex,
                usingEvaluatedItems: false,
                usingEvaluatedProperties: true,
                resultsCollector: resultsCollector);
                try
                {
                    Evaluate(parentDocument, parentIndex, ref context);
                    context.EndContext();
                    return context.IsMatch;
                }
                finally
                {
                    context.Dispose();
                }
            }

